// // This module implements a 16-bit binary counter that decrements on the rising edge of the clock when the enable signal is low. If the reset signal is high, the counter should be set to zero.
module counter_16bit (  
    input clk,  
    input reset,  
    input enable,  
    output reg [15:0] count  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 16'b0;  
        end else if (enable) begin  
            count <= count + 1;  
        end  
    end  
endmodule
